import{_ as t,o as r,c as e,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析 — 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6257_矽格/20260430/F17_籌碼分佈與法人動態分析_投資研究員.md","filePath":"審計報告庫/財務審計/6257_矽格/20260430/F17_籌碼分佈與法人動態分析_投資研究員.md"}'),l={name:"審計報告庫/財務審計/6257_矽格/20260430/F17_籌碼分佈與法人動態分析_投資研究員.md"};function o(n,a,s,h,_,c){return r(),e("div",null,[...a[0]||(a[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f17-籌碼分佈與法人動態分析-—-投資研究員-審計報告" tabindex="-1">F17: 籌碼分佈與法人動態分析 — 投資研究員 審計報告 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析-—-投資研究員-審計報告" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析 — 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>外資、投信與自營商的近期買賣超動向為何？千張大戶持股比例是否發生結構性變化？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：根據截至2026年4月最新公開數據，法人4月合計淨賣10.62M股。千張大戶佔比49.65%跌至45.28%，散戶增18.9%，屬「法人派發、散戶接貨」之結構性轉換。</li><li><strong>風險評級</strong>：高</li><li><strong>數據時效</strong>：根據截至2026年4月29日最新公開籌碼數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：投信4月淨賣12.61M股、外資淨買3.29M股、法人合計淨賣10.62M股。千張大戶佔比49.65%→45.28%，散戶增18.9%，融資11,472張。</li><li><strong>診斷見解</strong>：投信巨量拋售為近期罕見。千張大戶佔比連續4週下滑，散戶暴增符合「派發紅燈」。籌碼由強勢手流向弱勢手，風險高。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、法人買賣超" tabindex="-1">一、法人買賣超 <a class="header-anchor" href="#一、法人買賣超" aria-label="Permalink to &quot;一、法人買賣超&quot;">​</a></h3><ul><li><strong>核心重點</strong>：外資4月淨買3.29M股。投信淨賣12.61M股，4/8賣出1.65M、4/16賣出2.12M。自營+避險合計淨賣1.30M。法人合計淨賣10.62M。</li><li><strong>深度見解</strong>：投信4/8起幾乎每日賣超，為集體減碼行為。若投信持股佔比已高，此為結帳壓力體現，稍有風吹草動即可能引發踐踏效應。</li></ul><h3 id="二、千張大戶結構" tabindex="-1">二、千張大戶結構 <a class="header-anchor" href="#二、千張大戶結構" aria-label="Permalink to &quot;二、千張大戶結構&quot;">​</a></h3><ul><li><strong>核心重點</strong>：千張大戶佔比從1/30的49.65%（78戶）降至4/24的45.28%（72戶），持股數-8.8%。3月底曾反彈至48.66%後再度回落。</li><li><strong>深度見解</strong>：6戶退出千張大戶，持股數減少21M股。3月底反彈可能為除息前鎖碼，4月再度下滑確認減持為結構性趨勢。若跌破45%，技術面賣壓可能共振放大。</li></ul><h3 id="三、散戶與融資" tabindex="-1">三、散戶與融資 <a class="header-anchor" href="#三、散戶與融資" aria-label="Permalink to &quot;三、散戶與融資&quot;">​</a></h3><ul><li><strong>核心重點</strong>：散戶戶數從50,293增至59,836（+18.9%），持股佔比0.42%→0.61%。融資4/29為11,472張（4/22高點13,146張），融資使用率9.48%。借券97張。</li><li><strong>深度見解</strong>：散戶人數暴增但持股佔比僅升0.19 bps，代表大量散戶以小額參與。融資從高點回落反映部分散戶已停損，借券僅97張空方力道薄弱。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：三大法人4月合計淨賣10.62M股，投信單月淨賣12.61M股為主要壓力源。若投信持續減碼，法人拋壓將延長修正時間。千張大戶從49.65%跌至45.28%，大戶減持趨勢未止。若跌破45%關卡，技術面賣壓可能共振放大。</li><li><strong>空頭風險二</strong>：散戶戶數暴增18.9%但持股佔比僅升至0.61%，大量散戶以小額參與，一旦股價下跌易引發恐慌拋售。融資維持萬張以上，槓桿未完全出清，散戶槓桿風險持續累積。若融資追繳價被觸及，斷頭賣壓將加速下跌，形成負反饋循環，多殺多風險升溫。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind institutional</strong>: OK — 4月19交易日法人買賣超完整（外資+3.29M、投信-12.61M、合計-10.62M）</li><li><strong>FinMind backer_holding</strong>: OK — 1月至4月股權分散表12週次（千張49.65%→45.28%、散戶+18.9%）</li><li><strong>融資借券</strong>: OK — goodinfo.tw（融資11,472張、使用率9.48%、借券97張，截至4/29）</li><li><strong>關鍵核對碼</strong>: 投信淨賣12,611,708股；千張78→72戶；散戶50,293→59,836戶</li></ul>',19)])])}const g=t(l,[["render",o]]);export{u as __pageData,g as default};
